import React, { useState, useEffect } from "react";
import { Link } from "react-router-dom";
import "./Notes.css";
import { useAuth } from "../context/AuthContext";
import axios from "axios";

export default function Notes() {
  const { currentUser } = useAuth();
  const [notes, setNotes] = useState([]);
  const [file, setFile] = useState(null);
  const [title, setTitle] = useState("");
  const [searchTerm, setSearchTerm] = useState("");

  const fetchNotes = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/notes");
      setNotes(res.data);
    } catch (err) {
      console.error("Failed to fetch notes:", err);
    }
  };

  useEffect(() => {
    fetchNotes();
  }, []);

  useEffect(() => {
    fetch("http://localhost:5000/api/studyresources")
      .then((res) => res.json())
      .then((data) => setResources(data));
  }, []);


  const handleFileUpload = async (e) => {
    e.preventDefault();

    if (!file || !title) return alert("Please enter title and choose a file");

    const formData = new FormData();
    formData.append("file", file);
    formData.append("title", title);
    formData.append("uploadedBy", currentUser?.name);
    formData.append("role", currentUser?.role);

    try {
      await axios.post("http://localhost:5000/api/notes/upload", formData);
      setFile(null);
      setTitle("");
      fetchNotes();
    } catch (err) {
      console.error("Upload failed:", err);
    }
  };

  const handleDelete = async (id) => {
    if (currentUser?.role !== "admin") return;

    try {
      await axios.delete(`http://localhost:5000/api/notes/${id}`);
      fetchNotes();
    } catch (err) {
      console.error("Delete failed:", err);
    }
  };

  const filteredNotes = notes.filter((note) =>
    note.title.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="notes-page">
      <h1 className="notes-heading">Notes Section</h1>

      <form onSubmit={handleFileUpload} className="upload-form">
        <input
          type="text"
          placeholder="Enter note title"
          value={title}
          onChange={(e) => setTitle(e.target.value)}
          required
        />
        <input
          type="file"
          accept=".pdf,.doc,.docx"
          onChange={(e) => setFile(e.target.files[0])}
          required
        />
        <button type="submit">Upload</button>
      </form>

      <input
        type="text"
        placeholder="Search notes..."
        value={searchTerm}
        onChange={(e) => setSearchTerm(e.target.value)}
        className="search-input"
      />

      <div className="notes-list">
        {filteredNotes.map((note) => (
          <div className="note-card" key={note._id}>
            <h3>{note.title}</h3>
            <p>
              Uploaded by: <strong>{note.uploadedBy}</strong>
            </p>
            <p>Date: {new Date(note.createdAt).toLocaleDateString()}</p>
            <a href={note.fileUrl} target="_blank" rel="noopener noreferrer">
              View File
            </a>
            {currentUser?.role === "admin" && (
              <button onClick={() => handleDelete(note._id)} className="delete-btn">
                Delete
              </button>
            )}
          </div>
        ))}
      </div>

      <hr />

        {/* Study Resources Section */}
      <div style={{ padding: "2rem 1rem" }}>
        <h2 style={{ fontWeight: "bold", marginBottom: "1rem" }}>
          📚 Study Resources to Learn and Revise
        </h2>
        <div style={{
          display: "grid",
          gridTemplateColumns: "repeat(auto-fit, minmax(200px, 1fr))",
          gap: "1.5rem"
        }}>
          {/* Resource Cards */}
          {[
            {
              name: "W3Schools",
              desc: "Learn HTML, CSS, JavaScript, and more with simple tutorials.",
              img: "https://www.w3schools.com/images/w3schools_green.jpg",
              url: "https://www.w3schools.com/"
            },
            {
              name: "GeeksforGeeks",
              desc: "Master programming concepts, algorithms, and coding questions.",
              img: "https://media.geeksforgeeks.org/wp-content/cdn-uploads/gfg_200x200-min.png",
              url: "https://www.geeksforgeeks.org/"
            },
            {
              name: "freeCodeCamp",
              desc: "Learn coding by building projects with free full-length courses.",
              img: "https://design-style-guide.freecodecamp.org/downloads/fcc_primary_small.jpg",
              url: "https://www.freecodecamp.org/"
            },
            {
              name: "MDN Web Docs",
              desc: "The best official docs for web technologies like HTML, CSS, JS.",
              img: "https://developer.mozilla.org/mdn-social-share.0ca9dbda.png",
              url: "https://developer.mozilla.org/"
            },
            {
              name: "JavaTpoint",
              desc: "Simple explanations for Java, Python, C, C++, Web Dev topics.",
              img: "https://static.javatpoint.com/images/logo/jtp_logo.png",
              url: "https://www.javatpoint.com/"
            },
            {
              name: "Programiz",
              desc: "Easy tutorials and examples for Python, C, C++, Java beginners.",
              img: "https://upload.wikimedia.org/wikipedia/commons/thumb/5/59/Programiz_logo.png/600px-Programiz_logo.png",
              url: "https://www.programiz.com/"
            }
          ].map((resource, idx) => (
            <div key={idx} style={{
              border: "1px solid #eee",
              borderRadius: "10px",
              boxShadow: "0 2px 5px rgba(0,0,0,0.1)",
              padding: "1rem",
              textAlign: "center",
              backgroundColor: "#fff"
            }}>
              <img
                src={resource.img}
                alt={resource.name}
                style={{ width: "60px", height: "60px", objectFit: "contain", marginBottom: "10px" }}
              />
              <h4>{resource.name}</h4>
              <p style={{ fontSize: "0.85rem", color: "#555", minHeight: "60px" }}>{resource.desc}</p>
              <a href={resource.url} target="_blank" rel="noopener noreferrer">
                <button style={{
                  backgroundColor: "#00cba9",
                  border: "none",
                  color: "#fff",
                  padding: "8px 16px",
                  borderRadius: "4px",
                  cursor: "pointer"
                }}>
                  Visit
                </button>
              </a>
            </div>
          ))}
        </div>
      </div>
      <Link to="/dashboard" className="back-link">← Back to Dashboard</Link>
    </div>
  );
}
